import{_ as t,o as a,c as d,a3 as o}from"./chunks/framework.BveOjhN0.js";const u=JSON.parse('{"title":"Central admin UI","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Central admin UI | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/user-guide/admin-ui"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Central admin UI | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/user-guide/admin-ui"}]]},"headers":[],"relativePath":"user-guide/admin-ui.md","filePath":"user-guide/admin-ui.md","lastUpdated":1784746021000}'),n={name:"user-guide/admin-ui.md"};function r(i,e,s,c,l,p){return a(),d("div",null,[...e[0]||(e[0]=[o('<h1 id="central-admin-ui" tabindex="-1">Central admin UI <a class="header-anchor" href="#central-admin-ui" aria-label="Permalink to &quot;Central admin UI&quot;">​</a></h1><p>App: <code>SaaS-Frontend</code> (React 19 + Vite).</p><p>Central Application routes are prefixed with <code>/central</code>. Tenant auth uses root paths (<code>/login</code>, <code>/register</code>, …). See <a href="/developer-guide/authentication">authentication/authentication-developer.md</a>.</p><h2 id="navigation" tabindex="-1">Navigation <a class="header-anchor" href="#navigation" aria-label="Permalink to &quot;Navigation&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Group</th><th>Screens</th><th>Route</th></tr></thead><tbody><tr><td>Overview</td><td>Dashboard</td><td><code>/central/dashboard</code></td></tr><tr><td>Platform</td><td>Tenants, Users, Roles</td><td><code>/central/tenants</code>, <code>/central/users</code>, <code>/central/roles</code></td></tr><tr><td>Catalog</td><td>Marketplace, Modules</td><td><code>/central/marketplace</code>, <code>/central/modules</code></td></tr><tr><td>Billing</td><td>Dashboard, Invoices, Payments, Transactions, Refunds, Payment Methods, Payment Gateways, Coupons, Taxes, Billing Logs</td><td><code>/central/billing</code>, <code>/central/billing/*</code></td></tr><tr><td>Settings</td><td>Settings, Profile</td><td><code>/central/settings</code>, <code>/central/profile</code></td></tr></tbody></table><p>Tenant Application uses the <strong>same AppLayout shell</strong> with its own nav (<code>/dashboard</code>, <code>/leads</code>, <code>/tasks</code>, <code>/settings</code>, <code>/profile</code>). Workspace Settings (<code>/settings</code>) covers General, Branding, and Mail with Central fallbacks — see <a href="/user-guide/tenant-settings-overview">settings/tenant-settings.md</a>. Shared shell notes: <a href="/user-guide/shared-layout">ui/shared-layout.md</a>.</p><p>Auth:</p><table tabindex="0"><thead><tr><th>Screen</th><th>Route</th></tr></thead><tbody><tr><td>Central login</td><td><code>/central/login</code></td></tr><tr><td>Central forgot / reset</td><td><code>/central/forgot-password</code>, <code>/central/reset-password/{token}</code></td></tr><tr><td>Tenant login / register</td><td><code>/login</code>, <code>/register</code></td></tr><tr><td>Tenant forgot / reset</td><td><code>/forgot-password</code>, <code>/reset-password/{token}</code></td></tr><tr><td>Tenant dashboard</td><td><code>/dashboard</code></td></tr><tr><td>Registration closed</td><td><code>/registration-closed</code></td></tr></tbody></table><p>Removed from navigation: Plans, Limits, Tenant Subscriptions.</p><p>Not in the sidebar (reached via in-page links): <code>/central/tenants/:id</code>, <code>/central/roles/matrix</code>.</p><h2 id="screen-↔-api-map" tabindex="-1">Screen ↔ API map <a class="header-anchor" href="#screen-↔-api-map" aria-label="Permalink to &quot;Screen ↔ API map&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Screen</th><th>Primary APIs</th></tr></thead><tbody><tr><td>Tenants</td><td><code>/tenants</code>, archive/unarchive/restore/force</td></tr><tr><td>Tenant details</td><td><code>/tenants/{id}</code>, <code>/tenants/{id}/entitlements</code>, <code>/tenants/{id}/invoices</code>, <code>/tenants/{id}/payments</code>, <code>/tenants/{id}/modules</code>, <code>/tenants/{id}/impersonate</code></td></tr><tr><td>Marketplace</td><td><code>/marketplace/modules</code>, <code>/marketplace/modules/{id}</code>, install via <code>/tenants/{id}/modules</code></td></tr><tr><td>Module subscriptions</td><td><code>/module-subscriptions</code>, cancel/deactivate</td></tr><tr><td>Users</td><td><code>/users</code>, invite, activity, suspend, change-password</td></tr><tr><td>Roles</td><td><code>/roles</code>, clone, permissions-matrix</td></tr><tr><td>Modules (admin catalog)</td><td><code>/modules</code></td></tr><tr><td>Dashboard</td><td><code>/dashboard</code></td></tr><tr><td>Settings</td><td><code>/system-settings</code></td></tr><tr><td>Billing dashboard</td><td><code>/payment-gateways</code>, <code>/invoices</code>, <code>/payments</code></td></tr><tr><td>Payment Gateways</td><td><code>/payment-gateways</code>, enable/disable/default/config/mode/test-connection/logs; <strong>Product Mapping</strong> for Stripe (<code>price_…</code>) and Creem (<code>prod_…</code>)</td></tr><tr><td>Invoices / Payments (global)</td><td><code>/invoices</code>, <code>/payments</code></td></tr></tbody></table><h2 id="marketplace-marketplace" tabindex="-1">Marketplace (<code>/marketplace</code>) <a class="header-anchor" href="#marketplace-marketplace" aria-label="Permalink to &quot;Marketplace (`/marketplace`)&quot;">​</a></h2><ul><li>Lists published modules from <code>GET /marketplace/modules</code> (search, category filter)</li><li>Detail drawer/page: <code>GET /marketplace/modules/{id}?tenant_id=</code> for dependency + install state</li><li><strong>Install to workspace</strong>: select tenant → <code>POST /tenants/{tenant}/modules</code> with <code>module_id</code>, optional <code>billing_cycle</code></li><li>Today only Leads/Tasks appear (included, non-billable); UI supports future paid modules</li></ul><h2 id="tenants" tabindex="-1">Tenants <a class="header-anchor" href="#tenants" aria-label="Permalink to &quot;Tenants&quot;">​</a></h2><h3 id="tenant-details-tenants-id" tabindex="-1">Tenant details (<code>/tenants/:id</code>) <a class="header-anchor" href="#tenant-details-tenants-id" aria-label="Permalink to &quot;Tenant details (`/tenants/:id`)&quot;">​</a></h3><p>Tabbed layout:</p><table tabindex="0"><thead><tr><th>Tab</th><th>Content</th><th>APIs</th></tr></thead><tbody><tr><td><strong>Overview</strong></td><td>Contact, domain, localization, logo, timeline</td><td><code>GET /tenants/{id}</code></td></tr><tr><td><strong>Modules</strong></td><td>Installed subscriptions — status, source, price; cancel/deactivate actions</td><td><code>installed_modules</code> on tenant, <code>/module-subscriptions/...</code></td></tr><tr><td><strong>Billing</strong></td><td>Invoice and payment history tables</td><td><code>/tenants/{id}/invoices</code>, <code>/tenants/{id}/payments</code></td></tr></tbody></table><p>Header actions:</p><ul><li>Lifecycle: edit, archive, delete, restore, force-delete</li><li><strong>Impersonate</strong> (<code>impersonation.start</code>): reason dialog → <code>POST /tenants/{id}/impersonate</code>; end via <code>POST /impersonation/{id}/end</code></li></ul><p>Plan subscription and usage-limit cards removed.</p><h2 id="modules-admin-catalog" tabindex="-1">Modules (admin catalog) <a class="header-anchor" href="#modules-admin-catalog" aria-label="Permalink to &quot;Modules (admin catalog)&quot;">​</a></h2><p>List (<code>/modules</code>): name, slug, status, default-included / billable flags, pricing.</p><h3 id="module-form" tabindex="-1">Module form <a class="header-anchor" href="#module-form" aria-label="Permalink to &quot;Module form&quot;">​</a></h3><p>Fields: name, slug, description, icon, category, monthly/yearly price, status, <code>is_default_included</code>, <code>is_billable</code>, sort order, active.</p><p>Only Leads and Tasks exist in the seeded catalog. Modules are licensing products only — user access is managed via Spatie Roles &amp; Permissions.</p><h2 id="dashboard" tabindex="-1">Dashboard <a class="header-anchor" href="#dashboard" aria-label="Permalink to &quot;Dashboard&quot;">​</a></h2><ul><li>Welcome hero, growth chart, quick actions (Tenants / Users / Modules / Marketplace)</li><li>Recent tenants, recent activity</li><li>Revenue from billable module subscriptions (MRR is <code>0</code> while only included modules exist)</li></ul><h2 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h2><p>Tabs: General, Localization, Mail, Branding, Security, Maintenance, Billing.</p><table tabindex="0"><thead><tr><th>Tab</th><th>Behavior</th></tr></thead><tbody><tr><td><strong>General</strong></td><td>Application Name (title/sidebar), Company Name (copyright/emails), searchable timezone/locale/currency, registration toggle</td></tr><tr><td><strong>Localization</strong></td><td>Predefined date formats + 12/24h time — drives <code>formatAppDate</code> / <code>formatAppDateTime</code> app-wide</td></tr><tr><td><strong>Mail</strong></td><td>Full SMTP + From identity; send test email</td></tr><tr><td><strong>Branding</strong></td><td>Button color (CSS <code>--primary</code>), support email, logo/favicon file uploads with preview</td></tr><tr><td><strong>Security</strong></td><td>Session timeout minutes; min password length; require special character</td></tr><tr><td><strong>Maintenance</strong></td><td>Tenant-only. Central remains operational. Optional ETA.</td></tr><tr><td><strong>Billing</strong></td><td>Invoice prefix, proration mode, default gateway, trial/Stripe flags</td></tr></tbody></table><p>Public routes: <code>/register</code> shows the dedicated “We are not currently accepting new registrations.” page when registration is off. <code>/maintenance</code> renders branded tenant maintenance copy from public settings.</p><p>Bootstrap: <code>GET /public/settings</code> loads branding/formats on app start (Central never enters Laravel maintenance mode from this flag).</p><h2 id="command-palette" tabindex="-1">Command palette <a class="header-anchor" href="#command-palette" aria-label="Permalink to &quot;Command palette&quot;">​</a></h2><p><code>⌘K</code> / <code>Ctrl+K</code> — permission-filtered nav items.</p><p>No CRM/tenant-product UI in Central.</p>',36)])])}const h=t(n,[["render",r]]);export{u as __pageData,h as default};
